import * as React from "react";

import { cn } from "@/lib/utils";

import "./squeeze-animation.css";

export type SqueezeAnimationProps = React.ComponentPropsWithoutRef<"div"> & {
  /** Horizontal rebound distance. Numeric values are converted to px. Set to 0 to disable. */
  shakeX?: number | string;
  /** Vertical rebound distance. Numeric values are converted to px. Set to 0 to disable. */
  shakeY?: number | string;
  /** Animation duration. Numeric values are converted to ms. */
  duration?: number | string;
};

export function SqueezeAnimation({
  className,
  duration,
  shakeX,
  shakeY,
  style,
  ...props
}: SqueezeAnimationProps) {
  const animationStyle =
    duration === undefined && shakeX === undefined && shakeY === undefined
      ? style
      : ({
          ...style,
          ...(duration !== undefined
            ? { "--squeeze-animation-duration": formatDurationValue(duration) }
            : {}),
          ...(shakeX !== undefined
            ? { "--squeeze-animation-shake-x": formatShakeValue(shakeX) }
            : {}),
          ...(shakeY !== undefined
            ? { "--squeeze-animation-shake-y": formatShakeValue(shakeY) }
            : {}),
        } as React.CSSProperties);

  return (
    <div
      data-slot="squeeze-animation"
      className={cn(
        "squeeze-animation flex flex-col items-center text-foreground",
        className,
      )}
      style={animationStyle}
      {...props}
    >
      <svg
        viewBox="0 0 100 100"
        aria-hidden="true"
        className="squeeze-animation-svg h-auto w-full max-w-80"
      >
        <g className="squeeze-animation-icon">
          <rect
            x="26"
            y="30"
            width="48"
            height="40"
            rx="12"
            fill="currentColor"
            fillOpacity="0.1"
            stroke="currentColor"
            strokeWidth="6"
          />
          <path
            d="M 38 46 H 62"
            fill="none"
            stroke="currentColor"
            strokeLinecap="round"
            strokeWidth="6"
          />
          <path
            d="M 38 58 H 54"
            fill="none"
            stroke="currentColor"
            strokeLinecap="round"
            strokeWidth="6"
          />
        </g>
      </svg>
    </div>
  );
}

function formatShakeValue(value: number | string | undefined) {
  return typeof value === "number" ? `${value}px` : value;
}

function formatDurationValue(value: number | string | undefined) {
  return typeof value === "number" ? `${value}ms` : value;
}

.squeeze-animation {
  --squeeze-animation-duration: 1080ms;
  --squeeze-animation-shake-x: 4px;
  --squeeze-animation-shake-y: 2.5px;
}

.squeeze-animation-icon {
  transform-box: fill-box;
  transform-origin: center;
  animation: squeeze-animation var(--squeeze-animation-duration) both;
  will-change: transform;
}

@keyframes squeeze-animation {
  0% {
    transform: translate(0, 0) scale(1);
    animation-timing-function: cubic-bezier(0.645, 0.045, 0.355, 1);
  }
  22%,
  30% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * -0.28),
        calc(var(--squeeze-animation-shake-y) * 0.32)
      )
      scale(1.34, 0.68);
    animation-timing-function: cubic-bezier(0.19, 1, 0.22, 1);
  }
  40% {
    transform: translate(
        var(--squeeze-animation-shake-x),
        calc(var(--squeeze-animation-shake-y) * -1)
      )
      scale(0.8, 1.22);
    animation-timing-function: cubic-bezier(0.455, 0.03, 0.515, 0.955);
  }
  54% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * -0.55),
        calc(var(--squeeze-animation-shake-y) * 0.46)
      )
      scale(1.1, 0.91);
    animation-timing-function: cubic-bezier(0.455, 0.03, 0.515, 0.955);
  }
  72% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * 0.26),
        calc(var(--squeeze-animation-shake-y) * -0.24)
      )
      scale(0.975, 1.03);
    animation-timing-function: cubic-bezier(0.455, 0.03, 0.515, 0.955);
  }
  92% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * -0.09),
        calc(var(--squeeze-animation-shake-y) * 0.08)
      )
      scale(1.012, 0.992);
    animation-timing-function: cubic-bezier(0.455, 0.03, 0.515, 0.955);
  }
  100% {
    transform: translate(0, 0) scale(1);
  }
}

@media (prefers-reduced-motion: reduce) {
  .squeeze-animation-icon {
    animation: none;
    will-change: auto;
  }
}
